const rawOutput = $input.first().json.output;
const cleanHtml = rawOutput
  .replace(/\\n/g, ' ')
  .replace(/\n/g, ' ')
  .replace(/\\"/g, '"')
  .replace(/```html|```/g, '')
  .trim();
return { html: cleanHtml };

const body = $('Webhook - Upload Template').item.json.body;
const fileData = body.file;
const fileName = body.fileName || 'upload.jpg';

const binaryData = Buffer.from(fileData, 'base64');

return {
  json: { fileName },
  binary: {
    data: await this.helpers.prepareBinaryData(binaryData, fileName)
  }
};

